#include <stdio.h>
#include <string.h>
#define MOD 1000000007

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        static int freq[200005];
        memset(freq, 0, (N + 2) * sizeof(int));
        int maxVal = 0;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            freq[x]++;
            if (x > maxVal) maxVal = x;
        }
        long long ans = 0, prod = 1;
        for (int m = 1; m <= maxVal; ++m) {
            if (freq[m] == 0) break;
            prod = (prod * freq[m]) % MOD;
            ans = (ans + prod) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

