const data = fs.readFileSync(0, 'utf8').trim().split(/\s+/).map(Number);
let idx = 0;
const MOD = 1000000007n;
const T = data[idx++];
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = data[idx++];
  const freq = new Array(N + 2).fill(0);
  let maxVal = 0;
  for (let i = 0; i < N; ++i) {
    const x = data[idx++];
    freq[x]++;
    if (x > maxVal) maxVal = x;
  }
  let ans = 0n;
  let prod = 1n;
  for (let m = 1; m <= maxVal; ++m) {
    if (freq[m] === 0) break;
    prod = (prod * BigInt(freq[m])) % MOD;
    ans = (ans + prod) % MOD;
  }
  outputs.push(ans.toString());
}
